mapper.insert:
insert into courses (course_name, course_location, course_lecturer, course_date)
    select #{course.courseName}, #{course.courseLocation}, #{course.courseLecturer}, #{course.courseDate}
        where not exists (select course_name from courses where course_name = #{course.courseName});

mapper.update:
update
courses set
course_name = #{course.courseName}, course_location = #{course.courseLocation}, course_lecturer = #{course.courseLecturer}, course_date = #{course.courseDate}
where course_name = #{course.courseName};

mapper.select:
select course_name, course_location, course_lecturer, course_date
from courses
where course_name like concat('%',#{courseName},'%');

select course_name, course_location, course_lecturer, course_date
from courses
where course_date like concat('%',#{courseDate},'%');
